def decode_hieroglyphic_sum(hieroglyphs: str) -> int:
    hieroglyph_values = {'I': 1, 'V': 5, 'X': 10}
    total = 0

    for i in range(len(hieroglyphs)):
        value = hieroglyph_values[hieroglyphs[i]]
        if i > 0 and hieroglyph_values[hieroglyphs[i - 1]] < value:
            total += value - 2 * hieroglyph_values[hieroglyphs[i - 1]]
        else:
            total += value

    return total
